import { cva, type VariantProps } from 'class-variance-authority';
import { Badge } from '@/components/ui/badge';
import { resolveStatusTone, type StatusTone } from '@/constants/statuses';
import { cn } from '@/lib/utils';

const toneVariants = cva('', {
  variants: {
    tone: {
      neutral: 'border-transparent bg-muted text-muted-foreground',
      info: 'border-transparent bg-blue-500/15 text-blue-700 dark:text-blue-300',
      warning: 'border-transparent bg-orange-500/15 text-orange-800 dark:text-orange-300',
      success: 'border-transparent bg-emerald-500/15 text-emerald-800 dark:text-emerald-300',
      danger: 'border-transparent bg-destructive/15 text-destructive',
    },
  },
  defaultVariants: {
    tone: 'neutral',
  },
});

export interface StatusBadgeProps extends VariantProps<typeof toneVariants> {
  status: string;
  domain?: 'trip' | 'vehicle' | 'driver';
  label?: string;
  className?: string;
}

export function StatusBadge({ status, domain = 'trip', label, tone, className }: StatusBadgeProps) {
  const resolvedTone: StatusTone = tone ?? resolveStatusTone(status, domain);
  const display = label ?? status.replace(/_/g, ' ');

  return (
    <Badge variant="outline" className={cn(toneVariants({ tone: resolvedTone }), className)}>
      {display}
    </Badge>
  );
}
