/**
 * Status label → visual tone mapping per ui-design-system.md
 */

export type StatusTone = 'neutral' | 'info' | 'warning' | 'success' | 'danger';

export const TRIP_STATUS_TONES: Record<string, StatusTone> = {
  PENDING: 'neutral',
  ASSIGNED: 'info',
  IN_PROGRESS: 'warning',
  COMPLETED: 'success',
  CANCELLED: 'danger',
};

export const VEHICLE_STATUS_TONES: Record<string, StatusTone> = {
  ACTIVE: 'success',
  IN_TRIP: 'warning',
  IN_MAINTENANCE: 'info',
  AVAILABLE: 'success',
  BUSY: 'warning',
  MAINTENANCE: 'info',
  OUT_OF_SERVICE: 'danger',
};

export const DRIVER_STATUS_TONES: Record<string, StatusTone> = {
  ACTIVE: 'success',
  IN_TRIP: 'warning',
  INACTIVE: 'neutral',
  SUSPENDED: 'danger',
};

export function resolveStatusTone(
  status: string,
  domain: 'trip' | 'vehicle' | 'driver' = 'trip',
): StatusTone {
  const normalized = status.toUpperCase().replace(/\s+/g, '_');
  const map =
    domain === 'vehicle'
      ? VEHICLE_STATUS_TONES
      : domain === 'driver'
        ? DRIVER_STATUS_TONES
        : TRIP_STATUS_TONES;

  return map[normalized] ?? 'neutral';
}
